async function verify(url, label) {
  const r = await fetch(url, { cache: 'no-store' });
  const text = await r.text();
  const activeRule = /body\s*\{[^}]*overscroll-behavior-y:\s*none;/.test(text.slice(0, 400));
  const hasRemovalComment = text.includes('overscroll-behavior-y: none; REMOVED');
  console.log(label);
  console.log('  url:', url);
  console.log('  status:', r.status);
  console.log('  active overscroll-behavior-y: none on body:', activeRule);
  console.log('  has removal comment:', hasRemovalComment);
  console.log('  etag:', r.headers.get('etag'));
  console.log('  x-cache:', r.headers.get('x-cache'));
  console.log('  last-modified:', r.headers.get('last-modified'));
  console.log('  date:', r.headers.get('date'));
  return !activeRule && hasRemovalComment;
}

const ok1 = await verify('https://ivxholding.com/', 'CloudFront HTTPS');
const ok2 = await verify('https://s3.us-east-1.amazonaws.com/ivxholding.com/index.html', 'S3 Origin');
console.log('\n✅ Both sources serve the fixed landing page:', ok1 && ok2);

