const REMOTE = new TextEncoder().encode(''); // placeholder so file parses; we read remote at runtime

const repo = 'ibb142/rork-global-real-estate-invest';
const filePath = 'expo/ivxholding-landing/index.html';
const branch = 'main';

function exec(cmd) {
  const { execSync } = await import('node:child_process');
  return execSync(cmd, { encoding: 'utf-8', timeout: 30000 }).trim();
}

async function run() {
  const { execSync } = await import('node:child_process');
  const remoteUrl = execSync('git remote get-url github', { encoding: 'utf-8', timeout: 10000 }).trim();
  const tokenMatch = remoteUrl.match(/github\.com\/([^/]+)\/([^/.]+)/);
  if (!tokenMatch) throw new Error('Could not parse GitHub remote URL');
  const tokenMatch2 = remoteUrl.match(/^(https?:\/\/)([^@]+)@github\.com/);
  const token = tokenMatch2 ? tokenMatch2[2] : '';
  if (!token) throw new Error('No GitHub token in remote URL');

  const apiBase = 'https://api.github.com';
  const headers = {
    Authorization: `token ${token}`,
    Accept: 'application/vnd.github+json',
    'Content-Type': 'application/json',
    'User-Agent': 'ivx-deploy-agent',
  };

  // Get current file metadata on main
  const metaRes = await fetch(`${apiBase}/repos/${repo}/contents/${filePath}?ref=${branch}`, { headers });
  if (!metaRes.ok) throw new Error(`Failed to fetch file metadata: ${metaRes.status} ${await metaRes.text()}`);
  const meta = await metaRes.json();
  const currentSha = meta.sha;

  // Read local modified file
  const content = readFileSync(filePath, 'utf-8');
  const base64 = Buffer.from(content).toString('base64');

  // Update file on GitHub
  const updateRes = await fetch(`${apiBase}/repos/${repo}/contents/${filePath}`, {
    method: 'PUT',
    headers,
    body: JSON.stringify({
      message: 'fix(landing): remove overscroll-behavior-y:none to unblock mobile scroll-up',
      content: base64,
      sha: currentSha,
      branch,
    }),
  });
  const updateJson = await updateRes.json();
  if (!updateRes.ok) throw new Error(`Failed to update file: ${updateRes.status} ${JSON.stringify(updateJson)}`);
  console.log('✅ Committed index.html to GitHub:', updateJson.commit?.html_url);

  // Trigger workflow dispatch for deploy-landing.yml
  const dispatchRes = await fetch(`${apiBase}/repos/${repo}/actions/workflows/deploy-landing.yml/dispatches`, {
    method: 'POST',
    headers,
    body: JSON.stringify({ ref: branch }),
  });
  if (dispatchRes.status === 204) {
    console.log('🚀 Triggered deploy-landing.yml workflow on', branch);
  } else {
    const text = await dispatchRes.text();
    throw new Error(`Workflow dispatch failed: ${dispatchRes.status} ${text}`);
  }
}

run().catch((err) => {
  console.error('❌ Deploy failed:', err.message);
  process.exit(1);
});
